{
    "level": "B1",
    "intro": "У цій темі ти навчишся поєднувати підсилювачі з прикметниками та прислівниками: <strong>very, really, so, too, absolutely, quite, rather, pretty</strong>.",
    "rules": [
        {
            "label": "GRADABLE",
            "color": "emerald",
            "text": "Зі звичайними gradable adjectives часто вживаємо <strong>very / really / pretty / quite</strong>.",
            "example": "very cold / really good / quite busy"
        },
        {
            "label": "STRONG",
            "color": "blue",
            "text": "Зі strong adjectives природніше звучить <strong>absolutely / completely / totally</strong>.",
            "example": "absolutely amazing / completely impossible"
        },
        {
            "label": "TOO",
            "color": "amber",
            "text": "<strong>Too</strong> означає «більше, ніж треба / ніж добре».",
            "example": "too expensive / too late"
        }
    ]
}

{
    "title": "1. Найуживаніші підсилювачі",
    "intro": "Корисно знати не лише значення, а й типові поєднання.",
    "items": [
        {
            "label": "звичайне підсилення",
            "title": "very / really / pretty / quite",
            "subtitle": "very busy, really happy, pretty good, quite small"
        },
        {
            "label": "сильний прикметник",
            "title": "absolutely / completely / totally",
            "subtitle": "absolutely amazing, completely wrong"
        },
        {
            "label": "забагато",
            "title": "too + adjective",
            "subtitle": "too noisy, too heavy, too late"
        },
        {
            "label": "достатність",
            "title": "adjective + enough",
            "subtitle": "warm enough, fast enough"
        }
    ]
}

{
    "title": "2. Як вибирати природне слово",
    "sections": [
        {
            "label": "Very, really, so, quite",
            "color": "emerald",
            "description": "Ці слова часто стоять перед <strong>gradable adjectives</strong> і прислівниками.",
            "examples": [
                {
                    "en": "It is very cold today.",
                    "ua": "Сьогодні дуже холодно."
                },
                {
                    "en": "She is really friendly.",
                    "ua": "Вона справді привітна."
                },
                {
                    "en": "The room was quite small.",
                    "ua": "Кімната була досить маленька."
                }
            ]
        },
        {
            "label": "Absolutely, completely, totally",
            "color": "blue",
            "description": "Ці підсилювачі часто краще підходять до <strong>strong adjectives</strong>.",
            "examples": [
                {
                    "en": "The view was absolutely amazing.",
                    "ua": "Краєвид був абсолютно неймовірний."
                },
                {
                    "en": "That answer is completely wrong.",
                    "ua": "Ця відповідь повністю неправильна."
                },
                {
                    "en": "I am totally exhausted.",
                    "ua": "Я повністю виснажений."
                }
            ],
            "note": "Фрази на кшталт <em>very amazing</em> можливі рідше і часто звучать слабше."
        },
        {
            "label": "Too і enough",
            "color": "amber",
            "description": "<strong>Too</strong> має негативний відтінок, а <strong>enough</strong> показує достатність.",
            "examples": [
                {
                    "en": "This bag is too heavy.",
                    "ua": "Ця сумка надто важка."
                },
                {
                    "en": "The water is warm enough now.",
                    "ua": "Вода тепер достатньо тепла."
                },
                {
                    "en": "He is not old enough to drive.",
                    "ua": "Він ще недостатньо дорослий, щоб водити."
                }
            ],
            "note": "Пам’ятай порядок: <strong>too + adjective</strong>, але <strong>adjective + enough</strong>."
        }
    ]
}

{
    "title": "3. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Very зі strong adjective.",
            "wrong": "The film was very amazing.",
            "right": "✅ <span class=\"font-mono\">The film was absolutely amazing.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Too замість very.",
            "wrong": "The food is too good.",
            "right": "✅ <span class=\"font-mono\">The food is very good.</span> <span class=\"text-slate-500\">(якщо це позитивне значення)</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Неправильне місце enough.",
            "wrong": "The room is enough big.",
            "right": "✅ <span class=\"font-mono\">The room is big enough.</span>"
        }
    ]
}

{
    "title": "4. Короткий конспект",
    "items": [
        "<strong>Very / really / quite / pretty</strong> часто йдуть зі звичайними gradable adjectives.",
        "<strong>Absolutely / completely / totally</strong> часто пасують до strong adjectives.",
        "<strong>Too</strong> = більше, ніж треба; часто має негативний зміст.",
        "<strong>Enough</strong> стоїть після прикметника: <em>warm enough</em>.",
        "Вибирай підсилювач не лише за силою, а й за типом прикметника."
    ]
}

